import heapq
import math
from collections import defaultdict


def _coord_tuple(c):
    if isinstance(c, dict):
        c = c.get('coords', c.get('coord', c.get('pos', c)))
    return (float(c[0]), float(c[1]))


def _key(c, ndigits=3):
    c = _coord_tuple(c)
    return (round(c[0], ndigits), round(c[1], ndigits))


def _dist(a, b):
    ax, ay = _coord_tuple(a)
    bx, by = _coord_tuple(b)
    return math.hypot(ax - bx, ay - by)


class GraphUtilityPlanner:
    """Deterministic graph exploration planner for cogniplan_env.

    The planner searches the current sparse exploration graph and chooses a
    positive-utility target node according to a configurable utility-distance
    objective. It returns the first waypoint along the shortest graph path, which
    is compatible with env.step(target) because it is snapped to obs['neighbors'].
    """

    DEFAULTS = {
        'alpha': 1.0,
        'beta': 1.0,
        'utility_power': 1.0,
        'visited_penalty': 0.0,
        'mode': 'ratio',
        'lambda_dist': 0.02,
        'prefer_unvisited': 0.0,
        'nearest_fallback': True,
        'min_gain': 1e-9,
    }

    def __init__(self, alpha=1.0, beta=1.0, utility_power=1.0, visited_penalty=0.0,
                 mode='ratio', lambda_dist=0.02, prefer_unvisited=0.0,
                 nearest_fallback=True, min_gain=1e-9):
        self.alpha = float(alpha)
        self.beta = float(beta)
        self.utility_power = float(utility_power)
        self.visited_penalty = float(visited_penalty)
        self.mode = str(mode)
        self.lambda_dist = float(lambda_dist)
        self.prefer_unvisited = float(prefer_unvisited)
        self.nearest_fallback = bool(nearest_fallback)
        self.min_gain = float(min_gain)

    @classmethod
    def from_config(cls, cfg):
        d = dict(cls.DEFAULTS)
        if cfg:
            d.update({k: v for k, v in cfg.items() if k in d})
        return cls(**d)

    def to_config(self):
        return {
            'alpha': self.alpha,
            'beta': self.beta,
            'utility_power': self.utility_power,
            'visited_penalty': self.visited_penalty,
            'mode': self.mode,
            'lambda_dist': self.lambda_dist,
            'prefer_unvisited': self.prefer_unvisited,
            'nearest_fallback': self.nearest_fallback,
            'min_gain': self.min_gain,
        }

    def _build_graph(self, obs):
        nodes = obs.get('nodes', []) or []
        graph = defaultdict(list)
        node_info = {}
        coord_by_key = {}
        for n in nodes:
            if not isinstance(n, dict) or 'coords' not in n:
                continue
            c = _coord_tuple(n['coords'])
            k = _key(c)
            coord_by_key[k] = c
            node_info[k] = n
        for n in nodes:
            if not isinstance(n, dict) or 'coords' not in n:
                continue
            k = _key(n['coords'])
            kc = coord_by_key.get(k, _coord_tuple(n['coords']))
            for nb in n.get('neighbors', []) or []:
                nk = _key(nb)
                nc = coord_by_key.get(nk, _coord_tuple(nb))
                coord_by_key.setdefault(nk, nc)
                w = _dist(kc, nc)
                graph[k].append((nk, w))
                graph[nk].append((k, w))
        return graph, node_info, coord_by_key

    def _dijkstra(self, graph, start_key):
        pq = [(0.0, start_key)]
        dist = {start_key: 0.0}
        prev = {}
        while pq:
            d, u = heapq.heappop(pq)
            if d != dist.get(u):
                continue
            for v, w in graph.get(u, []):
                nd = d + w
                if nd < dist.get(v, 1e30):
                    dist[v] = nd
                    prev[v] = u
                    heapq.heappush(pq, (nd, v))
        return dist, prev

    def _first_step(self, start_key, target_key, prev, coord_by_key, legal_neighbors):
        if target_key == start_key:
            return None
        cur = target_key
        seen = 0
        while prev.get(cur) is not None and prev[cur] != start_key and seen < 10000:
            cur = prev[cur]
            seen += 1
        cand = coord_by_key.get(cur)
        if cand is None:
            return None
        ck = _key(cand)
        for nb in legal_neighbors:
            if _key(nb) == ck:
                return _coord_tuple(nb)
        return cand

    def _candidate_score(self, util, d, visited):
        u = max(float(util), 0.0)
        if u <= 0:
            return -1e30
        if visited:
            u *= max(0.0, 1.0 - self.visited_penalty)
        else:
            u *= (1.0 + self.prefer_unvisited)
        up = max(u, self.min_gain) ** self.utility_power
        dd = max(float(d), 0.0)
        if self.mode == 'linear':
            return up - self.lambda_dist * dd
        if self.mode == 'highutil':
            return up * 1000.0 - dd
        if self.mode == 'nearest':
            return -dd + self.lambda_dist * up
        # default ratio
        return up / ((dd + self.alpha) ** self.beta)

    def select_waypoint(self, obs):
        neighbors = obs.get('neighbors', []) or []
        if len(neighbors) == 0:
            return None
        if len(neighbors) == 1:
            return _coord_tuple(neighbors[0])

        robot = _coord_tuple(obs.get('robot_pos', (0.0, 0.0)))
        start_key = _key(robot)
        graph, node_info, coord_by_key = self._build_graph(obs)
        coord_by_key.setdefault(start_key, robot)

        for nb in neighbors:
            nk = _key(nb)
            coord_by_key.setdefault(nk, _coord_tuple(nb))
            w = _dist(robot, nb)
            graph[start_key].append((nk, w))
            graph[nk].append((start_key, w))

        dist, prev = self._dijkstra(graph, start_key)
        best_key, best_score, best_d = None, -1e30, 1e30
        for k, n in node_info.items():
            if k not in dist:
                continue
            util = float(n.get('utility', 0.0) or 0.0)
            if util <= 0:
                continue
            visited = bool(n.get('visited', False))
            d = dist[k]
            s = self._candidate_score(util, d, visited)
            if s > best_score or (abs(s - best_score) < 1e-12 and d < best_d):
                best_score, best_key, best_d = s, k, d

        if best_key is not None:
            step = self._first_step(start_key, best_key, prev, coord_by_key, neighbors)
            if step is not None:
                return step

        if self.nearest_fallback:
            # Greedy fallback among legal neighbours by their own node utility,
            # otherwise shortest immediate move. This avoids returning None before
            # the environment explicitly terminates.
            best_nb, best_s = None, -1e30
            for nb in neighbors:
                nk = _key(nb)
                n = node_info.get(nk, {})
                util = float(n.get('utility', 0.0) or 0.0)
                visited = bool(n.get('visited', False))
                s = self._candidate_score(util if util > 0 else self.min_gain, _dist(robot, nb), visited)
                if s > best_s:
                    best_s, best_nb = s, nb
            if best_nb is not None:
                return _coord_tuple(best_nb)
        return _coord_tuple(neighbors[0])


class TypeAdaptivePlanner:
    def __init__(self, cfg):
        self.cfg = cfg or {}
        base = dict(self.cfg)
        base.pop('type_configs', None)
        self.default_cfg = base
        self.type_configs = self.cfg.get('type_configs', {}) if isinstance(self.cfg, dict) else {}

    def planner_for_type(self, env_type):
        cfg = dict(self.default_cfg)
        if env_type in self.type_configs:
            cfg.update(self.type_configs[env_type])
        return GraphUtilityPlanner.from_config(cfg)
